arguments.command:
# The SGen worker frames resolved to mapping symbols. Let's look up the actual functions using nm
DBGFILE="/tmp/symbols/libmonosgen-2.0.so.debug"

echo "=== Looking up actual functions near SGen worker addresses ==="
# Get all function symbols sorted by address, then find the ones containing our addresses
nm -C --defined-only -n "$DBGFILE" 2>/dev/null | awk '
  /^[0-9a-f]+ [tTwW]/ {
    addr = strtonum("0x" $1)
    name = ""
    for(i=3;i<=NF;i++) name = name (i>3?" ":"") $i
    if (prev_addr > 0) {
      if (prev_addr <= 0x2f4b20 && addr > 0x2f4b20) print "0x2f4b20 => " prev_name " + " sprintf("0x%x", 0x2f4b20 - prev_addr)
      if (prev_addr <= 0x2f4c84 && addr > 0x2f4c84) print "0x2f4c84 => " prev_name " + " sprintf("0x%x", 0x2f4c84 - prev_addr)
    }
    prev_addr = addr
    prev_name = name
  }
'

