SOFILE="/tmp/symbols/libmonosgen-2.0.so"

# Try readelf with symbol table from the .so (dynsym)
echo "=== Dynamic symbols near 0x2f4b20 and 0x2f4c84 ==="
readelf -s --wide "$SOFILE" 2>/dev/null | awk '{
  if ($2 ~ /^[0-9a-f]+$/) {
    addr = strtonum("0x" $2)
    size = strtonum($3)
    if (addr > 0 && addr <= 0x2f4b20 && (addr + size) > 0x2f4b20) print "0x2f4b20 in: " $0
    if (addr > 0 && addr <= 0x2f4c84 && (addr + size) > 0x2f4c84) print "0x2f4c84 in: " $0
  }
}'

echo ""
echo "=== Trying DWARF info ==="
readelf --debug-dump=info "$DBGFILE" 2>/dev/null | grep -B5 -A5 "DW_AT_low_pc.*0x2f4" | head -30", "description": "Search dynsym and DWARF for SGen addresses", "initial_wait": 30}

